SELECT id, teacher_profile_id, student_profile_id, active_time, last_msg_id, status, create_time, update_time FROM room WHERE teacher_profile_id = #{teacherProfileId} AND status = 1
AND id < #{cursor}
ORDER BY id DESC LIMIT #{pageSize}

